### 2-2. Redis 캐시 전략

파일 위치: `domain/src/main/kotlin/com/maum/backend/service/call/CallMatchingService.kt`

```kotlin
// After: Redis 캐시 + 비동기 처리 적용
@Service
class CallMatchingService(
    private val callWaitingRepository: CallWaitingRepository,
    private val blockRepository: BlockRepository,
    private val redisTemplate: StringRedisTemplate,
    private val applicationEventPublisher: ApplicationEventPublisher,
) {
    companion object {
        // Redis 키 상수
        private const val WAITING_POOL_KEY = "call:waiting:pool"           // Sorted Set (score=timestamp)
        private const val USER_BLOCK_LIST_PREFIX = "call:block:"            // Set
        private const val USER_PROFILE_CACHE_PREFIX = "call:profile:"      // Hash
        private const val BLOCK_LIST_TTL_SECONDS = 300L                    // 5분
        private const val PROFILE_CACHE_TTL_SECONDS = 600L                 // 10분
    }

    // Before: DB 쿼리 102회 → After: Redis 조회 3회 + DB 쿼리 1회
    @Transactional(readOnly = true)
    fun findMatch(requesterId: String, requesterProfile: MatchProfileDto): CallWaitingWithProfileDto? {
        // 캐시 1: Redis Sorted Set에서 대기열 조회 (DB 접근 없음)
        val waitingPoolJson = redisTemplate.opsForZSet()
            .rangeByScoreWithScores(
                WAITING_POOL_KEY,
                0.0,
                System.currentTimeMillis().toDouble() - 5000, // 5초 이상 대기한 유저만
            ) ?: return null

        // 캐시 2: 요청자 차단 목록 Redis에서 일괄 조회
        val blockedUserIds = redisTemplate.opsForSet()
            .members("$USER_BLOCK_LIST_PREFIX$requesterId")
            ?: emptySet()

        // 후보군 필터링 (Redis 데이터만으로 처리, DB 없음)
        val candidates = waitingPoolJson
            .filter { it.value !in blockedUserIds }
            .filter { entry ->
                val profile = getProfileFromCache(entry.value)
                profile != null && isCompatible(requesterProfile, profile)
            }
            .take(1)

        return candidates.firstOrNull()?.let { entry ->
            callWaitingRepository.findByUserId(entry.value)
        }
    }

    // Redis 캐시에서 프로필 조회 (TTL: 10분)
    private fun getProfileFromCache(userId: String): CachedProfileDto? {
        val key = "$USER_PROFILE_CACHE_PREFIX$userId"
        val cached = redisTemplate.opsForHash<String, String>().entries(key)
        if (cached.isEmpty()) return null

        return CachedProfileDto(
            gender = cached["gender"]?.toInt() ?: return null,
            age = cached["age"]?.toInt() ?: return null,
            preferredGender = cached["preferredGender"]?.toInt() ?: return null,
            minPreferredAge = cached["minPreferredAge"]?.toInt() ?: return null,
            maxPreferredAge = cached["maxPreferredAge"]?.toInt() ?: return null,
        )
    }

    // 대기열 진입 시 Redis Sorted Set에 추가
    @Transactional
    fun enterWaitingPool(userId: String, profile: CachedProfileDto) {
        // DB 저장
        val waiting = callWaitingRepository.save(
            CallWaitingEntity(userId = userId, status = CallWaitingStatus.WAITING.value)
        )

        // Redis 대기열에 추가 (score = 현재 timestamp)
        redisTemplate.opsForZSet().add(
            WAITING_POOL_KEY,
            userId,
            System.currentTimeMillis().toDouble(),
        )

        // 프로필 캐싱 (10분 TTL)
        val key = "$USER_PROFILE_CACHE_PREFIX$userId"
        redisTemplate.opsForHash<String, String>().putAll(
            key,
            mapOf(
                "gender" to profile.gender.toString(),
                "age" to profile.age.toString(),
                "preferredGender" to profile.preferredGender.toString(),
                "minPreferredAge" to profile.minPreferredAge.toString(),
                "maxPreferredAge" to profile.maxPreferredAge.toString(),
            )
        )
        redisTemplate.expire(key, Duration.ofSeconds(PROFILE_CACHE_TTL_SECONDS))
    }

    // 매칭 확정: 비동기 알림 처리
    @Transactional
    fun confirmMatch(waitingId: String, matchedUserId: String) {
        val waiting = callWaitingRepository.findById(waitingId).orElseThrow()
        waiting.status = CallWaitingStatus.MATCHED.value
        callWaitingRepository.save(waiting)

        // Redis 대기열에서 제거 (무효화)
        redisTemplate.opsForZSet().remove(WAITING_POOL_KEY, waiting.userId)
        redisTemplate.opsForZSet().remove(WAITING_POOL_KEY, matchedUserId)

        // 알림 비동기 처리 (Spring Event → @Async)
        applicationEventPublisher.publishEvent(
            MatchConfirmedEvent(
                userId = waiting.userId,
                matchedUserId = matchedUserId,
            )
        )
    }

    // 차단 목록 캐시 갱신 (유저가 차단 추가/삭제 시 호출)
    fun refreshBlockListCache(userId: String) {
        val blockedIds = blockRepository.findBlockedUserIds(userId)
        val key = "$USER_BLOCK_LIST_PREFIX$userId"

        redisTemplate.delete(key)
        if (blockedIds.isNotEmpty()) {
            redisTemplate.opsForSet().add(key, *blockedIds.toTypedArray())
            redisTemplate.expire(key, Duration.ofSeconds(BLOCK_LIST_TTL_SECONDS))
        }
    }
}
```

