### 2-3. 비동기 알림 처리

파일 위치: `call/src/main/kotlin/com/maum/backend/event/MatchConfirmedEventHandler.kt`

```kotlin
// After: 동기 알림 → 비동기 이벤트 처리로 응답 시간 단축
@Component
class MatchConfirmedEventHandler(
    private val notificationService: NotificationService,
) {
    // @Async로 별도 스레드에서 실행 → 매칭 API 응답 시간에서 알림 시간 제거
    @Async("matchingTaskExecutor")
    @TransactionalEventListener(phase = TransactionPhase.AFTER_COMMIT)
    fun handle(event: MatchConfirmedEvent) {
        notificationService.sendMatchNotification(event.userId, event.matchedUserId)
        notificationService.sendMatchNotification(event.matchedUserId, event.userId)
    }
}

// 전용 스레드풀 설정
@Configuration
@EnableAsync
class AsyncConfig {
    @Bean("matchingTaskExecutor")
    fun matchingTaskExecutor(): TaskExecutor =
        ThreadPoolTaskExecutor().apply {
            corePoolSize = 4
            maxPoolSize = 8
            queueCapacity = 100
            setThreadNamePrefix("match-notify-")
            initialize()
        }
}
```

