    ): List<CallWaitingWithProfileDto> {
        val waiting = QCallWaitingEntity.callWaitingEntity
        val profile = QUserProfileEntity.userProfileEntity

        return queryFactory
            .select(
                Projections.constructor(
                    CallWaitingWithProfileDto::class.java,
                    waiting.id,
                    waiting.userId,
                    profile.gender,
                    profile.age,
                    profile.mannerScore,
                    waiting.createdAt,
                )
            )
            .from(waiting)
            // 병목 해결: JOIN으로 프로필 한 번에 로드 (N+1 제거)
            .join(profile).on(profile.userId.eq(waiting.userId))
            .where(
                waiting.status.eq(CallWaitingStatus.WAITING.value),
                waiting.userId.ne(requesterId),
                // DB에서 성별/나이 필터링 (메모리 필터링 제거)
                profile.gender.eq(preferredGender),
                profile.age.between(minAge, maxAge),
                // 차단 목록을 IN 절로 한 번에 처리 (N+1 제거)
                blockedUserIds.takeIf { it.isNotEmpty() }
                    ?.let { waiting.userId.notIn(it) },
                // 5분 이상 된 대기자 우선 (FIFO 보장)
                waiting.createdAt.before(LocalDateTime.now().minusSeconds(5)),
            )
            .orderBy(waiting.createdAt.asc())
            .limit(10) // 후보군 10명만 조회
            .fetch()
    }
}
